applyRtl.code:
const RTL = '\u200F';
const text = $json.message;
return { json: { formatted: RTL + text } };

formatMixed.code:
const RTL = '\u200F';
const LTR = '\u200E';
const hebrew = $json.hebrew;
const english = $json.english;
return { json: { formatted: `${RTL}${hebrew}${LTR}${english}${RTL}` } };

formatCurrency.code:
const amount = $json.amount;
const formatted = `₪${amount.toLocaleString('he-IL')}`;
return { json: { formatted } };

formatPhone.code:
let phone = $json.phone.replace(/\D/g, '');
if (phone.startsWith('0')) {
  phone = '972' + phone.slice(1);
} else if (!phone.startsWith('972')) {
  phone = '972' + phone;
}
return { json: { formatted_phone: phone } };

formatDate.code:
const { DateTime } = require('luxon');
const date = DateTime.fromISO($json.date)
  .setZone('Asia/Jerusalem')
  .setLocale('he');
return {
  json: {
    date_short: date.toFormat('dd/MM/yyyy'),
    date_long: date.toFormat('EEEE, d MMMM yyyy'),
    time: date.toFormat('HH:mm')
  }
};
